#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N,K; scanf("%d %d",&N,&K);
        char *rowUsed = (char*)calloc(N+1,sizeof(char));
        char *colUsed = (char*)calloc(N+1,sizeof(char));
        for(int i=0;i<K;++i){int r,c;scanf("%d %d",&r,&c);rowUsed[r]=1;colUsed[c]=1;}
        int P = N - K;
        printf("%d",P);
        int rIdx=1,cIdx=1;
        for(int placed=0; placed<P; ++placed){
            while(rIdx<=N && rowUsed[rIdx]) ++rIdx;
            while(cIdx<=N && colUsed[cIdx]) ++cIdx;
            printf(" %d %d",rIdx,cIdx);
            ++rIdx; ++cIdx;
        }
        printf("\n");
        free(rowUsed); free(colUsed);
    }
    return 0;
}

